comptime {
    if (@sizeOf(usize) == 8) {
        if (@sizeOf(__AnonStruct17) != 24) @compileError("__AnonStruct17 size mismatch");
        if (@alignOf(__AnonStruct17) != 8) @compileError("__AnonStruct17 alignment mismatch");
    }
}

